import{c as n,Q as s,j as a,m as o}from"./chunks/framework.CBiVa4O3.js";const g=JSON.parse('{"title":"真实语言剖析","description":"","frontmatter":{},"headers":[],"relativePath":"../interpreterLearning/29-真实语言剖析.md","filePath":"../interpreterLearning/29-真实语言剖析.md","lastUpdated":1778496697000}'),e={name:"../interpreterLearning/29-真实语言剖析.md"};function r(c,t,d,p,i,l){return s(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="真实语言剖析" tabindex="-1">真实语言剖析 <a class="header-anchor" href="#真实语言剖析" aria-label="Permalink to &quot;真实语言剖析&quot;">​</a></h1><p>到这一篇为止,Mochi 已经走完了<strong>词法、语法、AST、树遍历解释、字节码 VM、mark-sweep GC</strong>——这些组件<strong>在每一门主流动态语言里都长得一模一样</strong>,只是命名和工程量不同。这一篇是<strong>全系列密度最高的对照篇</strong>——把 CPython / V8 / Lua / JVM 拆成几个维度,告诉你**&quot;Mochi 哪一篇 ↔ 这门语言哪个文件 / 类 / 函数&quot;**。读完 27 篇 Mochi 再看这一篇,<strong>你能直接去 clone CPython / Lua 仓库,半天看出关键路径</strong>——而不是被 50 万行 C 代码吓退。<strong>这一篇之后是不是再看天书,差距全在这里</strong>。</p><blockquote><p>一句话先记住:<strong>真实语言的核心组件不超过 Mochi 涉及的范围</strong>——词法 / 语法 / AST / 解释 / 字节码 / GC,只是工程化、性能优化、边界 case 的复杂度高一两个量级。<strong>Lua 5.4 全部源码 ~30k 行 C,周末 4 小时能啃完关键路径</strong>——这是入门工业级解释器最划算的一门。CPython / V8 / HotSpot 都是数十万行,<strong>直接读会迷路,带着&quot;对应到 Mochi 哪一篇&quot;的地图读才看得懂</strong>。</p></blockquote><hr><h2 id="一、四大语言核心文件对照表" tabindex="-1">一、四大语言核心文件对照表 <a class="header-anchor" href="#一、四大语言核心文件对照表" aria-label="Permalink to &quot;一、四大语言核心文件对照表&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>              | 词法           | 语法              | AST          | 解释执行              | 字节码          | GC</span></span>
<span class="line"><span>CPython 3.12  | tokenizer.c    | parser.c (PEG)    | pycore_ast.h | ceval.c               | bytecodes.c     | gcmodule.c</span></span>
<span class="line"><span>V8 (Chrome)   | scanner.cc     | parser.cc         | ast.h        | interpreter-          | bytecodes.h     | heap/ (Orinoco</span></span>
<span class="line"><span>              |                |                   |              | generator.cc          |                 | 并发分代)</span></span>
<span class="line"><span>Lua 5.4       | llex.c         | lparser.c         | -*           | lvm.c                 | lopcodes.h      | lgc.c</span></span>
<span class="line"><span>JVM HotSpot   | -**            | -**               | -**          | templateInterpreter.  | bytecodes.hpp   | gc/g1/  gc/z/</span></span>
<span class="line"><span>              |                |                   |              | cpp                   |                 | gc/shenandoah/</span></span></code></pre></div><p>* Lua <strong>没有显式 AST</strong>——parser 边解析边编译成字节码(single-pass) ** HotSpot 不做前端——javac 是另一个项目</p><p><strong>Mochi 篇 ↔ 上表对照</strong>:</p><table tabindex="0"><thead><tr><th>Mochi 篇</th><th>CPython</th><th>V8</th><th>Lua</th></tr></thead><tbody><tr><td>05 词法</td><td><code>Parser/tokenizer.c</code></td><td><code>parsing/scanner.cc</code></td><td><code>llex.c</code></td></tr><tr><td>07-09 语法</td><td><code>Parser/parser.c</code></td><td><code>parsing/parser.cc</code></td><td><code>lparser.c</code></td></tr><tr><td>10 AST</td><td><code>pycore_ast.h</code></td><td><code>ast/ast.h</code></td><td>(无)</td></tr><tr><td>21-25 字节码</td><td><code>Python/ceval.c</code></td><td><code>interpreter/</code></td><td><code>lvm.c</code></td></tr><tr><td>26-27 GC</td><td><code>Modules/gcmodule.c</code></td><td><code>heap/</code></td><td><code>lgc.c</code></td></tr></tbody></table><hr><h2 id="二、各家的-独门绝技-一行话" tabindex="-1">二、各家的&quot;独门绝技&quot;一行话 <a class="header-anchor" href="#二、各家的-独门绝技-一行话" aria-label="Permalink to &quot;二、各家的&quot;独门绝技&quot;一行话&quot;">​</a></h2><table tabindex="0"><thead><tr><th>语言</th><th>一句话本质</th><th>推荐难度</th></tr></thead><tbody><tr><td><strong>CPython</strong></td><td>GIL + 字节码 VM。3.11+ 加 specializing interpreter,3.13 开始拆 GIL</td><td>★★★</td></tr><tr><td><strong>V8</strong></td><td>高度优化的多 tier JIT(Ignition → Sparkplug → Maglev → TurboFan),文件最多最绕</td><td>★★★★★</td></tr><tr><td><strong>Lua 5.4</strong></td><td>寄存器式 VM + 极简增量 GC,<strong>~30k 行 C</strong>,<strong>可读性最好</strong></td><td>★</td></tr><tr><td><strong>JVM HotSpot</strong></td><td>模板解释器 + C1/C2 JIT,GC 选项多到爆炸(G1/ZGC/Shenandoah)</td><td>★★★★</td></tr><tr><td><strong>LuaJIT</strong></td><td>Lua + Tracing JIT,<strong>Mike Pall 一个人写的奇迹</strong>,动态语言性能上限</td><td>★★★</td></tr></tbody></table><p><strong>新手只看一家的话:从 Lua 开始,没有第二个选项</strong>。</p><hr><h2 id="三、关键数据结构对照" tabindex="-1">三、关键数据结构对照 <a class="header-anchor" href="#三、关键数据结构对照" aria-label="Permalink to &quot;三、关键数据结构对照&quot;">​</a></h2><p>读源码最快的方式不是从 main 看起,<strong>而是看核心数据结构</strong>——把它跟 Mochi 里的对照,瞬间就知道每个字段干嘛。</p><table tabindex="0"><thead><tr><th>维度</th><th>CPython</th><th>V8</th><th>Lua</th></tr></thead><tbody><tr><td>函数对象</td><td><code>PyFunctionObject</code>(func_code + globals + closure)</td><td><code>JSFunction</code>(SharedFunctionInfo + Context + Code)</td><td><code>LClosure</code>(Proto + upvals[])</td></tr><tr><td>调用栈</td><td><code>_PyInterpreterFrame</code>(3.11 改栈式后 +25%)</td><td>机器栈 + Ignition 寄存器</td><td><code>CallInfo</code></td></tr><tr><td>GC 头部</td><td><code>ob_refcnt + ob_type</code></td><td>hidden class(<code>Map</code>)</td><td><code>GCObject { next, tt, marked }</code></td></tr><tr><td>GC 策略</td><td>引用计数 + 分代追踪</td><td>Orinoco:并发 + 分代 + 增量</td><td>增量三色,可选分代</td></tr><tr><td>字符串</td><td>UCS1/2/4 三选一</td><td>ConsString / SlicedString / ...</td><td>短串 interned + 长串</td></tr><tr><td>整数</td><td><code>PyLongObject</code> 任意精度</td><td>SMI(31 位)或 <code>HeapNumber</code></td><td><code>lua_Integer</code> 64 位</td></tr></tbody></table><p><strong>Mochi 的 Closure { proto, upvalues[] } 几乎是 Lua 的简化版</strong>。<strong>V8 SharedFunctionInfo 把字节码和 closure 实例分开</strong>——为了一份字节码被多个 closure 共享。<strong>Mochi 的 CallFrame { ip, base, closure } 是 Lua CallInfo 的近亲</strong>——<code>ip</code> 在 Lua 里叫 <code>savedpc</code>,本质一样。<strong>Mochi GC 头部 { marked, next } 几乎就是 Lua 的 CommonHeader</strong>——写 GC 最教科书的做法。</p><p><strong>V8 字符串的&quot;分裂&quot;很出彩</strong>——<code>&quot;a&quot;+&quot;b&quot;+&quot;c&quot;</code> 不立即拼接,做成 ConsString(树状),<strong>真要 char access 时才扁平化</strong>——这是 JS 大量字符串拼接性能能撑住的关键。<strong>CPython 的引用计数是历史包袱</strong>——拆 GIL(3.13)后必须改成 biased reference counting。</p><hr><h2 id="四、cpython-拆解-mochi-视角" tabindex="-1">四、CPython 拆解:Mochi 视角 <a class="header-anchor" href="#四、cpython-拆解-mochi-视角" aria-label="Permalink to &quot;四、CPython 拆解:Mochi 视角&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. python my_script.py</span></span>
<span class="line"><span>2. tokenizer.c              ← Mochi 篇 05 词法</span></span>
<span class="line"><span>3. parser.c (PEG)           ← Mochi 篇 07-09 语法</span></span>
<span class="line"><span>4. compile.c                ← Mochi 篇 24 编译器</span></span>
<span class="line"><span>5. ceval.c (大 switch)      ← Mochi 篇 22 栈式 VM</span></span>
<span class="line"><span>6. gcmodule.c               ← Mochi 篇 26-27 GC</span></span></code></pre></div><p><strong>特色一</strong>:<strong>3.11 specializing interpreter</strong>(PEP 659)——<code>BINARY_ADD</code> 在运行时观察类型后,<strong>原地改成 <code>BINARY_ADD_INT</code></strong>。<strong>这是不用 JIT 的 JIT</strong>——单纯在解释器层做 type specialization,<strong>带来 ~30% 加速</strong>。</p><p><strong>特色二</strong>:<strong>3.13 no-GIL 实验</strong>——<code>python --disable-gil</code>。<strong>这是 Python 历史最大的内部重构</strong>。</p><p><strong>入口推荐</strong>:<code>Python/ceval.c</code> <code>_PyEval_EvalFrameDefault</code>(主调度循环)→ <code>Python/bytecodes.c</code>(所有字节码,3.12 用 DSL 生成)→ <code>Modules/gcmodule.c</code>。</p><hr><h2 id="五、v8-拆解-mochi-视角" tabindex="-1">五、V8 拆解:Mochi 视角 <a class="header-anchor" href="#五、v8-拆解-mochi-视角" aria-label="Permalink to &quot;五、V8 拆解:Mochi 视角&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>JS 源码 → scanner.cc → parser.cc → ast.h         ← Mochi 篇 05-10</span></span>
<span class="line"><span>→ interpreter-generator.cc 生成 Ignition 字节码   ← Mochi 篇 24</span></span>
<span class="line"><span>→ interpreter.cc 跑 Ignition                      ← Mochi 篇 22</span></span>
<span class="line"><span>→ ic/ 目录:inline cache                          ← (Mochi 不实现)</span></span>
<span class="line"><span>→ baseline / maglev / compiler:多 tier JIT       ← Mochi 篇 28</span></span>
<span class="line"><span>→ heap/ Orinoco GC                                ← Mochi 篇 27 工业版</span></span></code></pre></div><p><strong>入口推荐</strong>(按难度递增):<code>src/parsing/scanner.cc Scanner::Scan()</code> → <code>src/builtins/builtins-array.cc</code>(<code>Array.push</code> 内置)→ <code>src/compiler/pipeline.cc Pipeline::Run()</code>(TurboFan 主流程)→ <code>src/heap/heap.cc</code>。</p><p><strong>看源码的诀窍</strong>:<strong>不要从 main 看起</strong>——Chromium 的入口在浏览器代码里,V8 是嵌入库。<strong>从一个 builtin(<code>Array.push</code>)看起,反向追到字节码 → IC → JIT</strong>。</p><hr><h2 id="六、lua-拆解-周末-4-小时入门" tabindex="-1">六、Lua 拆解:周末 4 小时入门 <a class="header-anchor" href="#六、lua-拆解-周末-4-小时入门" aria-label="Permalink to &quot;六、Lua 拆解:周末 4 小时入门&quot;">​</a></h2><p><strong>这是本系列最强推荐</strong>——Lua 5.4 完整源码 ~30k 行 C,周末啃完关键路径。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/</span></span>
<span class="line"><span>├── lua.c          ← REPL 入口</span></span>
<span class="line"><span>├── llex.c (~700)  ← 词法</span></span>
<span class="line"><span>├── lparser.c (~1700) ← 语法 + 单遍编译到字节码</span></span>
<span class="line"><span>├── lopcodes.h     ← ~50 条指令</span></span>
<span class="line"><span>├── lvm.c (~1500)  ← 字节码 VM 主循环</span></span>
<span class="line"><span>├── lgc.c (~1400)  ← 增量三色 GC</span></span>
<span class="line"><span>├── lobject.h      ← 所有核心数据结构</span></span>
<span class="line"><span>├── ltable.c       ← Lua 表(数组+哈希)</span></span>
<span class="line"><span>└── lapi.c         ← C API</span></span></code></pre></div><h3 id="_4-小时阅读路线" tabindex="-1">4 小时阅读路线 <a class="header-anchor" href="#_4-小时阅读路线" aria-label="Permalink to &quot;4 小时阅读路线&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第 1 小时  → lobject.h(TValue / GCObject / Table / Proto / Closure)+ lopcodes.h</span></span>
<span class="line"><span>第 2 小时  → llex.c(llex 词法)+ lparser.c(luaY_parser / expr 递归下降)</span></span>
<span class="line"><span>第 3 小时  → lvm.c(luaV_execute 主循环)+ 对照 lopcodes.h 看 OP_ADD / OP_CALL</span></span>
<span class="line"><span>第 4 小时  → lgc.c(luaC_step 增量 GC)+ ltable.c(混合表实现)</span></span></code></pre></div><p><strong>为什么强推 Lua</strong>:代码风格统一(Roberto 团队 30 年一以贯之)、没有历史包袱、每个文件都自洽(不像 V8 一个改动牵动 50 个文件)、关键算法都有 paper 引用。<strong>做完 Lua 你看其他三家会觉得&quot;原来都差不多,只是工程化更狠&quot;</strong>。</p><hr><h2 id="七、jvm-hotspot-一行话" tabindex="-1">七、JVM HotSpot 一行话 <a class="header-anchor" href="#七、jvm-hotspot-一行话" aria-label="Permalink to &quot;七、JVM HotSpot 一行话&quot;">​</a></h2><p>JVM 最特别——<strong>没有前端</strong>(<code>javac</code> 是另一个项目),只接 <code>.class</code> 字节码:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hotspot/share/</span></span>
<span class="line"><span>├── interpreter/templateInterpreter.cpp   ← 模板解释器</span></span>
<span class="line"><span>├── c1/ opto/                             ← C1 / C2 JIT</span></span>
<span class="line"><span>├── gc/g1/ gc/z/ gc/shenandoah/ ...       ← 多种 GC</span></span>
<span class="line"><span>└── classfile/                            ← .class 文件解析</span></span></code></pre></div><p><strong>两个看点</strong>:<strong>C2 编译器</strong>(<code>opto/</code>)优化质量至今无对手;<strong>ZGC 做到了 200ms 堆上 &lt; 1ms 暂停</strong>——全球还没有第二个 GC 实现到这水平。<strong>JVM 字节码 200+ 条指令</strong>,是 Mochi 的 5-10 倍。</p><hr><h2 id="八、mochi-这里偷懒了" tabindex="-1">八、Mochi 这里偷懒了 <a class="header-anchor" href="#八、mochi-这里偷懒了" aria-label="Permalink to &quot;八、Mochi 这里偷懒了&quot;">​</a></h2><p><strong>Mochi 30 篇之后,真实语言的工程复杂度还是高一两个量级</strong>——不是知识体系上,<strong>而是工程化的厚度</strong>:</p><table tabindex="0"><thead><tr><th>维度</th><th>Mochi</th><th>工业级语言</th></tr></thead><tbody><tr><td>代码量</td><td>~5-8k 行 TS</td><td>Lua 30k / CPython 1M / V8 2M</td></tr><tr><td>测试用例</td><td>~200 个</td><td>CPython 60k+ / V8 100k+</td></tr><tr><td>平台适配</td><td>一个</td><td>5+(x86/ARM × Linux/Mac/Win)</td></tr><tr><td>优化 pass</td><td>0</td><td>C2 / TurboFan 各几十个</td></tr><tr><td>标准库</td><td>builtins ~20 个</td><td>CPython 200+ 模块</td></tr></tbody></table><p><strong>所以读源码时永远记得</strong>:<strong>核心算法是 Mochi 教过的那个,剩下的 90% 是工程化</strong>。</p><hr><h2 id="九、踩坑提醒" tabindex="-1">九、踩坑提醒 <a class="header-anchor" href="#九、踩坑提醒" aria-label="Permalink to &quot;九、踩坑提醒&quot;">​</a></h2><ol><li><strong>从 main 看起读不下去</strong>——main 在 CLI / 嵌入器里,核心在数据结构和主循环</li><li><strong>不画依赖图</strong>——V8 一万个 class,不画 component graph 永远看不懂</li><li><strong>跳过 lobject.h / objects/</strong>——核心数据结构没看清,后面符号全是黑盒</li><li><strong>以为字节码 = 机器码</strong>——V8 / CPython / Lua 三家字节码完全不同</li><li><strong>不读测试</strong>——V8 的 <code>test/mjsunit/</code> 是理解边界 case 的宝矿</li><li><strong>看版本不对齐</strong>——CPython 3.10 之前没 PEG parser、3.11 之前 frame 在堆上,看老博客容易踩</li><li><strong>比较代码量等于比较复杂度</strong>——Lua 30k vs V8 2M,<strong>功能差距没 60 倍</strong>,大部分是平台 / 兼容 / 优化</li><li><strong>学完一家就觉得&quot;懂解释器&quot;</strong>——学三家才有比较视角,<strong>Lua + CPython + V8 是黄金组合</strong></li></ol><hr><p>下一篇:<code>30-从Mochi到生产语言.md</code>,<strong>全系列收官</strong>——这一篇不再讲新概念,<strong>全是路线指引</strong>。Mochi 30 篇完成了什么、真要把它变&quot;能用的语言&quot;下一步往哪走(WASM / 增量编译 / LSP / JIT / 类型系统 / 并发)、读完之后你应该做的三件事。<strong>30 篇是起点,不是终点</strong>——这是这门&quot;反直觉训练&quot;最后想交给你的东西。</p>`,52)])])}const u=n(e,[["render",r]]);export{g as __pageData,u as default};
